class I18nStore {
	locale: Locale = $state('es');

	t(key: string): string {
		const entry = dict[key];
		if (!entry) return key;
		return entry[this.locale] ?? entry['en'] ?? key;
	}

	setLocale(l: Locale) {
		this.locale = l;
	}
}

export const i18n = new I18nStore();
export function t(key: string): string { return i18n.t(key); }
